sp_widget.client_script:
api.controller = function($scope) {
    var c = this;
    c.activeTab = 0;

    c.toggleRunning = function(assigner) {
        c.server.update({
            action: 'toggleRunning',
            assignerSysId: assigner.sys_id
        }).then(function() {
            assigner.running = !assigner.running;
        });
    };

    c.toggleWorking = function(assigner, entry) {
        var willWork = !entry.working;
        c.server.update({
            action: 'setWorking',
            rosterSysId: entry.sys_id,
            working: willWork
        }).then(function(response) {
            entry.working = willWork;
            // Re-sync this entry from the fresh server payload (server may have
            // auto-applied last_shift / default shift when moving into Working).
            var fresh = findRosterEntry(response.data, assigner.sys_id, entry.sys_id);
            if (fresh) {
                entry.shift = fresh.shift;
                entry.shift_sys_id = fresh.shift_sys_id;
            }
        });
    };

    c.setShift = function(entry) {
        c.server.update({
            action: 'setShift',
            rosterSysId: entry.sys_id,
            shiftSysId: entry.shift_sys_id
        });
    };

    function findRosterEntry(payload, assignerSysId, rosterSysId) {
        if (!payload || !payload.assigners) return null;
        for (var i = 0; i < payload.assigners.length; i++) {
            var a = payload.assigners[i];
            if (a.sys_id !== assignerSysId) continue;
            for (var j = 0; j < a.roster.length; j++) {
                if (a.roster[j].sys_id === rosterSysId) return a.roster[j];
            }
        }
        return null;
    }
};

sp_widget.css:
.aa-shell { padding: 16px 20px; }
.aa-shell h2 { margin-top: 0; }
.aa-empty { color: #888; font-style: italic; }

.aa-assigner { padding: 16px 4px; }

.aa-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    border-bottom: 1px solid #eee;
    padding-bottom: 12px;
    margin-bottom: 16px;
}
.aa-header h3 { margin: 0; }
.aa-meta { color: #666; font-size: 13px; margin-top: 2px; }

.aa-status { display: flex; align-items: center; gap: 12px; }
.aa-running { color: #2e7d32; font-weight: 600; }
.aa-stopped { color: #999; }
.aa-status .fa { margin-right: 4px; }

.aa-rosters {
    display: flex;
    gap: 16px;
    margin-top: 16px;
}
.aa-list {
    flex: 1;
    border: 1px solid #ddd;
    border-radius: 4px;
    padding: 12px 14px;
    background: #fafafa;
}
.aa-list h4 { margin: 0 0 10px 0; font-size: 14px; color: #444; }
.aa-list ul { list-style: none; padding: 0; margin: 0; }
.aa-list li {
    padding: 6px 0;
    border-bottom: 1px solid #efefef;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 8px;
}
.aa-name { flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.aa-row-controls { display: flex; align-items: center; gap: 6px; flex-shrink: 0; }
.aa-shift-select { font-size: 12px; padding: 2px 6px; height: auto; min-width: 110px; max-width: 160px; }
.aa-move-btn { padding: 2px 6px; }
.aa-list li:last-child { border-bottom: 0; }
.aa-empty-row { color: #999; }

.aa-shift-pill {
    background: #e3f2fd;
    color: #1565c0;
    padding: 2px 8px;
    border-radius: 10px;
    font-size: 12px;
}

sp_widget.script:
(function() {
    var SCOPE = 'x_1578378_aa_';
    var userSysId = gs.getUserID();
    var isAdmin   = gs.hasRole('admin');
    var isManager = gs.hasRole(SCOPE + 'queue_manager');

    handleInput();

    data.user      = gs.getUserDisplayName();
    data.isAdmin   = isAdmin;
    data.isManager = isManager;
    data.assigners = [];

    var ar = new GlideRecord(SCOPE + 'assigner');
    ar.orderBy('name');
    ar.query();
    while (ar.next()) {
        var groupSysId = ar.getValue('assignment_group');
        if (!isAdmin && (!groupSysId || !isUserInGroup(userSysId, groupSysId))) continue;

        data.assigners.push({
            sys_id: ar.getUniqueValue(),
            name: ar.name + '',
            assignment_group: ar.assignment_group.getDisplayValue() || '(none)',
            running: ar.running == true,
            canManage: canEditAssigner(ar),
            shifts: getShifts(ar.getUniqueValue()),
            roster: getRoster(ar.getUniqueValue())
        });
    }

    function handleInput() {
        if (!input || !input.action) return;
        switch (input.action) {
            case 'toggleRunning':
                var a = new GlideRecord(SCOPE + 'assigner');
                if (a.get(input.assignerSysId) && canEditAssigner(a)) {
                    a.running = (a.running != true);
                    a.update();
                }
                break;
            case 'setWorking':
                editRoster(input.rosterSysId, function(r) {
                    var willWork = !!input.working;
                    r.working = willWork;
                    // R4.6 — when moving into Working without a shift selected,
                    // prefer last_shift, else the assigner's Default shift.
                    if (willWork && !r.getValue('shift')) {
                        var preferred = r.getValue('last_shift') || findDefaultShift(r.getValue('assigner'));
                        if (preferred) r.shift = preferred;
                    }
                });
                break;
            case 'setShift':
                editRoster(input.rosterSysId, function(r) {
                    r.shift = input.shiftSysId || '';
                    if (input.shiftSysId) r.last_shift = input.shiftSysId;
                });
                break;
        }
    }

    function editRoster(rosterSysId, mutator) {
        if (!rosterSysId) return;
        var r = new GlideRecord(SCOPE + 'roster_entry');
        if (!r.get(rosterSysId)) return;
        var a = new GlideRecord(SCOPE + 'assigner');
        if (!a.get(r.getValue('assigner')) || !canEditAssigner(a)) return;
        mutator(r);
        r.update();
    }

    function findDefaultShift(assignerSysId) {
        var s = new GlideRecord(SCOPE + 'shift');
        s.addQuery('assigner', assignerSysId);
        s.addQuery('is_default', true);
        s.setLimit(1);
        s.query();
        return s.next() ? s.getUniqueValue() : null;
    }

    function canEditAssigner(a) {
        if (isAdmin) return true;
        if (!isManager) return false;
        var g = a.getValue('assignment_group');
        return !!g && isUserInGroup(userSysId, g);
    }

    function getShifts(assignerSysId) {
        var shifts = [];
        var s = new GlideRecord(SCOPE + 'shift');
        s.addQuery('assigner', assignerSysId);
        s.orderBy('name');
        s.query();
        while (s.next()) {
            shifts.push({
                sys_id: s.getUniqueValue(),
                name: s.name + ''
            });
        }
        return shifts;
    }

    function getRoster(assignerSysId) {
        var roster = [];
        var r = new GlideRecord(SCOPE + 'roster_entry');
        r.addQuery('assigner', assignerSysId);
        r.addQuery('active', true);
        r.orderBy('analyst');
        r.query();
        while (r.next()) {
            roster.push({
                sys_id: r.getUniqueValue(),
                analyst: r.analyst.getDisplayValue(),
                analyst_sys_id: r.getValue('analyst'),
                working: r.working == true,
                shift: r.shift.getDisplayValue(),
                shift_sys_id: r.getValue('shift')
            });
        }
        return roster;
    }

    function isUserInGroup(userSysId, groupSysId) {
        var m = new GlideRecord('sys_user_grmember');
        m.addQuery('user', userSysId);
        m.addQuery('group', groupSysId);
        m.setLimit(1);
        m.query();
        return m.hasNext();
    }
})();
